import React, { useState } from 'react';

export default function DataUpload() {
  const [file, setFile] = useState(null);
  const [uploading, setUploading] = useState(false);
  const [result, setResult] = useState(null);

  const handleFileChange = (e) => {
    setFile(e.target.files[0]);
    setResult(null);
  };

  const handleUpload = async () => {
    if (!file) return;

    setUploading(true);
    const formData = new FormData();
    formData.append('file', file);

    try {
      const response = await fetch('http://localhost:8000/upload_properties', {
        method: 'POST',
        body: formData,
      });
      const data = await response.json();
      setResult(data);
    } catch (err) {
      setResult({ error: err.message });
    }
    setUploading(false);
  };

  return (
    <div className="data-upload">
      <h2>📁 Upload Property Data</h2>
      <p>Upload CSV or Excel files with property data</p>

      <div className="form-group">
        <label>Select File (CSV or Excel)</label>
        <input 
          type="file" 
          accept=".csv,.xlsx,.xls"
          onChange={handleFileChange}
          style={{
            background: 'rgba(0,0,0,0.4)',
            border: '1px solid rgba(139,148,158,0.25)',
            borderRadius: '10px',
            padding: '0.875rem',
            color: '#fff',
            width: '100%'
          }}
        />
      </div>

      <button 
        onClick={handleUpload} 
        disabled={!file || uploading}
        className="btn"
        style={{ marginTop: '1rem' }}
      >
        {uploading ? 'Uploading...' : 'Upload & Analyze'}
      </button>

      {result && (
        <div className="result" style={{ marginTop: '1.5rem' }}>
          <h3>Analysis Results</h3>
          <pre style={{ whiteSpace: 'pre-wrap', color: '#e6edf3' }}>
            {JSON.stringify(result, null, 2)}
          </pre>
        </div>
      )}

      <div style={{ marginTop: '2rem', textAlign: 'left' }}>
        <h3>Expected CSV Format:</h3>
        <code style={{ color: '#8b949e', fontSize: '0.8rem' }}>
          address,price,bedrooms,bathrooms,sqft,year_built,rent_estimate
        </code>
        <p style={{ color: '#6e7681', fontSize: '0.85rem', marginTop: '0.5rem' }}>
          Example: 123 Main St,350000,3,2,1800,2010,2500
        </p>
      </div>
    </div>
  );
}
